 {"id":"bd-3bxhj.2.12","title":"task(opentui-import ingestion): Implement secret detection and artifact redaction pipeline","description":"Objective: Detect and redact sensitive tokens/credentials in source-derived artifacts, logs, and manifests while preserving debugging utility.\n\nAcceptance criteria:\n1. Secret scanners run on raw inputs and generated outputs.\n2. Redaction is deterministic, reversible only via secure local mapping, and traceable.\n3. Certification/replay artifacts never expose raw secrets.","status":"open","priority":0,"issue_type":"task","created_at":"2026-02-24T21:40:28.287338931Z","created_by":"ubuntu","updated_at":"2026-02-24T21:40:36.879638934Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["ingestion","opentui-import","provenance","security"],"dependencies":[{"issue_id":"bd-3bxhj.2.12","depends_on_id":"bd-3bxhj.2","type":"parent-child","created_at":"2026-02-24T21:40:28.287338931Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-3bxhj.2.12","depends_on_id":"bd-3bxhj.2.11","type":"blocks","created_at":"2026-02-24T21:40:36.879591715Z","created_by":"ubuntu","metadata":"{}","thread_id":""}]}
