 {"id":"bd-3bxhj.2.14","title":"task(opentui-import ingestion tests): E2E adversarial-ingestion script with security audit logging","description":"Objective: Build end-to-end adversarial ingestion suite (malicious scripts, path traversal attempts, oversized payloads, secret leakage probes) with deterministic security audit traces.\n\nAcceptance criteria:\n1. Script verifies fail-closed behavior under hostile fixture corpus.\n2. Security audit logs include policy decisions, blocked operations, and replay IDs.\n3. CI gate fails on sandbox bypass or unredacted-secret detection.","status":"open","priority":0,"issue_type":"task","created_at":"2026-02-24T21:40:29.275155153Z","created_by":"ubuntu","updated_at":"2026-02-24T21:40:39.697650784Z","source_repo":".","compaction_level":0,"original_size":0,"labels":["e2e","ingestion","opentui-import","security","test"],"dependencies":[{"issue_id":"bd-3bxhj.2.14","depends_on_id":"bd-3bxhj.1.7","type":"blocks","created_at":"2026-02-24T21:40:38.769848720Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-3bxhj.2.14","depends_on_id":"bd-3bxhj.2","type":"parent-child","created_at":"2026-02-24T21:40:29.275155153Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-3bxhj.2.14","depends_on_id":"bd-3bxhj.2.10","type":"blocks","created_at":"2026-02-24T21:40:39.226658508Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-3bxhj.2.14","depends_on_id":"bd-3bxhj.2.13","type":"blocks","created_at":"2026-02-24T21:40:39.697602724Z","created_by":"ubuntu","metadata":"{}","thread_id":""}]}

